module SRAM_Cell (  
    input wire [7:0] data,  
    input wire we,  
    input wire re,  
    output reg [7:0] q  
);  
    reg [7:0] memory;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge we or posedge dbg_halt) begin  
        memory <= data;  
    end  

    always @(posedge re) begin  
        q <= memory;  
    end  
endmodule
